```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Use varint_encode function from hexi::detail namespace
    // The function returns the number of bytes written
    return varint_encode<T>(writer, value);
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Use varint_decode function from hexi::detail namespace
    // The function returns the decoded value
    return varint_decode<T>(reader);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::uint8_t>> adaptor(buffer);

    // Create a binary_stream_writer using the adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);

    // Encode the original value
    std::size_t bytes_written = encode_varint(writer, original_value);

    // Create a binary_stream_reader using the same adaptor
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader);

    // Compare decoded value with original value
    return original_value == decoded_value;
}
```

