        return ReadLimitInfo{0, 0, 0, false}; // Success case
    } catch (const hexi::stream_read_limit& ex) {
        // Handle stream_read_limit exception
        return ReadLimitInfo{
            ex.read_size,    // Bytes attempted to read
            ex.total_read,   // Total bytes read so far
